  ('elementary-8b44517b-moex-00559', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '有關訴願審議程序規定，下列敘述何者錯誤？', '["訴願原則上採書面審理方式進行決定", "受理訴願機關認有必要時，得通知訴願人陳述意見", "訴願人請求陳述意見時，受理訴願機關即應聽取其陳述", "訴願審議委員會主任委員無須親自聽取訴願人陳述"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00560', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列何種行政訴訟種類，原則上須先踐行訴願程序？', '["課予義務訴訟", "確認訴訟", "一般給付訴訟", "公益訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00561', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '居住於新竹之甲因投資需求，向住於桃園之乙借款新臺幣 300 萬元，雙方並以書面約定若因該借貸 關係發生爭議，合意由臺灣桃園地方法院管轄。嗣後，甲因投資失利，逾期未償還向乙所借之款項， 乙乃向臺灣新竹地方法院聲請依督促程序對甲發支付命令。下列敘述何者錯誤？', '["若甲接獲支付命令後，未於20日內提出異議，該支付命令即告確定，並得為執行名義", "若甲主張支付命令上所載債權不存在而提起確認之訴，法院依債務人聲請，得許甲提供相當並確 實之擔保，停止強制執行", "甲得於支付命令確定5日後，向地方法院以欠缺管轄權為由聲請再審", "若甲接獲支付命令後第15日，提出異議但未附理由，仍屬有效之異議"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00562', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列關於民事訴訟審級之敘述，何者錯誤？', '["對於簡易程序之第一審裁判，得上訴或抗告於管轄之高等法院，其審判以合議行之", "對於小額程序之第一審裁判，得上訴或抗告於管轄之地方法院，其審判以合議行之", "上訴經撤回或因不合法而被駁回者，原則上附帶上訴失其效力", "上訴第三審法院，非以原判決違背法令為理由，不得為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00563', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列關於民事法院管轄之敘述，何者正確？', '["當事人得以合意定第一審及第二審管轄法院", "法院認為無管轄權者，原告與被告均得聲請以裁定移送於有管轄權之法院", "因侵權行為涉訟者，原告僅得於侵權行為地之法院起訴", "移送訴訟之聲請被駁回者，不得聲明不服"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00564', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列關於民事訴訟法規定必要共同訴訟人之敘述，何者錯誤？', '["共同訴訟人中一人之行為有利益於共同訴訟人者，其效力及於全體", "共同訴訟人中一人之行為不利於共同訴訟人者，對於全體不生效力", "他造對於共同訴訟人中一人之行為，其效力及於全體", "共同訴訟人中之一人與他造合意停止者，其停止之效力及於全體"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00565', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列何者係死亡宣告之法律效力？', '["被宣告死亡者，視為死亡", "被宣告死亡者之財產成為遺產", "被宣告死亡者喪失權利能力，縱然尚生存，亦無法為有效之法律行為", "被宣告死亡者若生還，得向法院聲請撤銷死亡宣告，回復一切能力與法律關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00566', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列關於代理之敘述，何者錯誤？', '["代理人所為或所受意思表示之效力，因其為限制行為能力人而受影響", "代理人經本人之許諾，或專履行債務者，得為自己代理", "代理權之限制及撤回，不得對抗無過失之善意第三人", "代理人依照本人所指示之意思而為代理時，其意思表示是否有被詐欺之事實，應就本人決之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
